function renomearParaPortugues() {
  // ID da sua pasta principal
  var folderId = '1b03aqoqbTF1JBpqCdOVMVTnMB-F8pIj8';
  var parentFolder = DriveApp.getFolderById(folderId);

  // Lista de traduções
  var traducoes = {
    // Pastas das Seleções
    '0 TODOS LOS EQUIPOS Calidad Media': '0 TODAS AS EQUIPES Qualidade Média',
    'ALEMANIA (Alta resolución)': 'ALEMANHA (Alta Resolução)',
    'ARGENTINA (Alta resolución)': 'ARGENTINA (Alta Resolução)',
    'BRASIL (Alta resolución)': 'BRASIL (Alta Resolução)',
    'COCA COLA (Alta resolución)': 'COCA-COLA (Alta Resolução)',
    'COLOMBIA (Alta resolución)': 'COLÔMBIA (Alta Resolução)',
    'CROACIA (Alta resolución)': 'CROÁCIA (Alta Resolução)',
    'ECUADOR (Alta resolución)': 'EQUADOR (Alta Resolução)',
    'ESPAÑA (Alta resolución)': 'ESPANHA (Alta Resolução)',
    'FRANCIA (Alta resolución)': 'FRANÇA (Alta Resolução)',
    'HOLANDA (Alta resolución)': 'HOLANDA (Alta Resolução)',
    'INGLATERRA (Alta resolución)': 'INGLATERRA (Alta Resolução)',
    'MARRUECOS (Alta resolución)': 'MARROCOS (Alta Resolução)',
    'MEXICO (Alta resolución)': 'MÉXICO (Alta Resolução)',
    'NEYMAR (Alta resolución)': 'NEYMAR (Alta Resolução)',
    'NORUEGA (Alta resolución)': 'NORUEGA (Alta Resolução)',
    'PORTUGAL (Alta resolución)': 'PORTUGAL (Alta Resolução)',
    'URUGUAY (Alta resolución)': 'URUGUAI (Alta Resolução)',

    // Arquivos PDF e Imagens
    'Album PDF 2026.pdf': 'Álbum PDF 2026.pdf',
    'Control de Figuritas_26.pdf': 'Controle de Figurinhas_26.pdf',
    'Doradas.pdf': 'Douradas.pdf',
    'Extra stickers Gold (1).pdf': 'Figurinhas Extras Douradas (1).pdf',
    'EXTRA STICKERS PARTE 1.pdf': 'FIGURINHAS EXTRAS PARTE 1.pdf',
    'Hologramas (1).pdf': 'Hologramas (1).pdf',
    'INFORMACIÓN PARA  IMPRESIÓN_.png': 'INFORMAÇÃO PARA IMPRESSÃO_.png',
    'SOBRES.pdf': 'ENVELOPES.pdf'
  };

  // Renomeando as Subpastas
  var folders = parentFolder.getFolders();
  while (folders.hasNext()) {
    var folder = folders.next();
    var nomeOriginal = folder.getName().trim();
    if (traducoes[nomeOriginal]) {
      folder.setName(traducoes[nomeOriginal]);
    }
  }

  // Renomeando os Arquivos
  var files = parentFolder.getFiles();
  while (files.hasNext()) {
    var file = files.next();
    var nomeOriginal = file.getName().trim();
    // Tratamento especial para nomes com espaços duplos ocultos
    for (var chave in traducoes) {
      if (nomeOriginal.replace(/\s+/g, ' ') === chave.replace(/\s+/g, ' ')) {
        file.setName(traducoes[chave]);
        break;
      }
    }
  }

  console.log('Sucesso! Tudo foi renomeado para Português.');
}
